defmodule CinderUI.Docs.SampleAssets do
  @moduledoc false

  alias CinderUI.Components.Advanced
  alias CinderUI.Components.DataDisplay

  @avatar_levi "data:image/jpeg;base64,"
  @avatar_shadcn "data:image/jpeg;base64,"
  @avatar_mira "data:image/jpeg;base64,"

  def hydrate_template_for_preview(snippet, DataDisplay, :avatar) do
    replace_first_example_image(avatar_sample_data_uri(:levi), snippet)
  end

  def hydrate_template_for_preview(snippet, DataDisplay, :avatar_group) do
    [:levi, :mira, :ari]
    |> Enum.map(&avatar_sample_data_uri/1)
    |> Enum.reduce(snippet, &replace_first_example_image/2)
  end

  def hydrate_template_for_preview(snippet, Advanced, :sidebar) do
    replace_first_example_image(avatar_sample_data_uri(:ari), snippet)
  end

  def hydrate_template_for_preview(snippet, Advanced, :sidebar_layout) do
    replace_first_example_image(avatar_sample_data_uri(:ari), snippet)
  end

  def hydrate_template_for_preview(snippet, Advanced, :sidebar_footer) do
    replace_first_example_image(avatar_sample_data_uri(:levi), snippet)
  end

  def hydrate_template_for_preview(snippet, Advanced, :sidebar_profile_menu) do
    replace_first_example_image(avatar_sample_data_uri(:ari), snippet)
  end

  def hydrate_template_for_preview(snippet, _module, _function), do: snippet

  defp replace_first_example_image(data_uri, snippet) when is_binary(snippet) do
    Regex.replace(
      ~r/src=(["'])example\.png\1/u,
      snippet,
      fn _full, quote -> "src=#{quote}#{data_uri}#{quote}" end,
      global: false
    )
  end

  defp avatar_sample_data_uri(:levi), do: @avatar_levi
  defp avatar_sample_data_uri(:ari), do: @avatar_shadcn
  defp avatar_sample_data_uri(:mira), do: @avatar_mira
  defp avatar_sample_data_uri(:noor), do: @avatar_mira
end
